<script lang="ts" setup>
const { locale, locales, setLocale } = useI18n()
const selected = ref(locale)

function handleSelect(e: Event) {
  if (e.target && 'value' in e.target) {
    const value = e.target.value
    if (locales.value.some(l => l.code === value)) {
      setLocale(value as typeof locale.value)
    }
  }
}
</script>

<template>
  <div
    class="relative flex flex-shrink-0 justify-between items-center w-16 text-slate-700"
  >
    <svg
      xmlns="http://www.w3.org/2000/svg"
      fill="none"
      viewBox="0 0 24 24"
      stroke-width="1.5"
      stroke="currentColor"
      class="absolute size-5 ml-2 pointer-events-none"
    >
      <path
        stroke-linecap="round"
        stroke-linejoin="round"
        d="M12 21a9.004 9.004 0 0 0 8.716-6.747M12 21a9.004 9.004 0 0 1-8.716-6.747M12 21c2.485 0 4.5-4.03 4.5-9S14.485 3 12 3m0 18c-2.485 0-4.5-4.03-4.5-9S9.515 3 12 3m0 0a8.997 8.997 0 0 1 7.843 4.582M12 3a8.997 8.997 0 0 0-7.843 4.582m15.686 0A11.953 11.953 0 0 1 12 10.5c-2.998 0-5.74-1.1-7.843-2.918m15.686 0A8.959 8.959 0 0 1 21 12c0 .778-.099 1.533-.284 2.253m0 0A17.919 17.919 0 0 1 12 16.5c-3.162 0-6.133-.815-8.716-2.247m0 0A9.015 9.015 0 0 1 3 12c0-1.605.42-3.113 1.157-4.418"
      />
    </svg>
    <label
      for="language"
      class="sr-only"
    >Choose a language:</label>
    <select
      id="language"
      v-model="selected"
      class="w-full pl-8 py-2 appearance-none bg-slate-100 rounded uppercase hover:opacity-80"
      @change="handleSelect"
    >
      <option
        v-for="loc in locales"
        :key="loc.code"
        :value="loc.code"
        :selected="loc.code === selected"
      >
        {{ loc.code }}
      </option>
    </select>
  </div>
</template>
